UPDATE archivio_items SET abstract = 'Prendendo spunto dal caso di Ferdinando Carretta, che dopo aver sterminato anni fa la propria famiglia, ha chiesto al Tribunale di ottenerne l''eredità, l''Alieno si occupa di figli che hanno ucciso i genitori: in analisi soprattutto la storia di Erika e Omar, ma anche quelle di Pietro Maso e di Doretta Graneri. Ospiti in studio il criminologo Carmelo Lavorino, Stefano Zecchi e Don Gino Rogoldi, cappellano del carcere minorile Beccaria (nel quale è rinchiusa Erika). Servizio intervista (realizzata da Oliviero Toscani) a Paolo Pasimeni, lo studente padovano che ha ucciso il padre dandogli fuoco. Il problema dello spirito di emulazione e di indentificazione che viene suscitato nei  giovani da questi personaggi.' WHERE id_originale = 2766;
